-- FSI_DEMO_DB.INSURANCE.CLAIMS

CREATE OR REPLACE TABLE FSI_DEMO_DB.INSURANCE.CLAIMS (

    CLAIM_ID VARCHAR(20) NOT NULL,
    POLICY_ID VARCHAR(20),
    POLICYHOLDER_ID VARCHAR(20),
    CLAIM_DATE DATE,
    INCIDENT_DATE DATE,
    REPORT_DATE DATE,
    CLAIM_TYPE VARCHAR(50),
    DESCRIPTION VARCHAR(16777216),
    LOCATION_CITY VARCHAR(100),
    LOCATION_STATE VARCHAR(2),
    CLAIMED_AMOUNT NUMBER(15,2),
    APPROVED_AMOUNT NUMBER(15,2),
    PAID_AMOUNT NUMBER(15,2),
    STATUS VARCHAR(30),
    ADJUSTER_ID VARCHAR(20),
    RESOLUTION_DATE DATE,
    FRAUD_FLAG BOOLEAN DEFAULT FALSE,
    FRAUD_SCORE NUMBER(5,4),
    SUBROGATION_FLAG BOOLEAN DEFAULT FALSE,
    LITIGATION_FLAG BOOLEAN DEFAULT FALSE,
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (CLAIM_ID)

);



